    51→      messageId: "sort",
    52→      loc: {
    53→        start: sourceCode.getLocFromIndex(start),
    54→        end: sourceCode.getLocFromIndex(end),
    55→      },
    56→      fix: (fixer) => fixer.replaceTextRange([start, end], sorted),
