    73→  // comment and there’s code (or a multiline block comment) on the same line,
    74→  // add a newline so we don’t accidentally comment stuff out.
    75→  const flattened = flatMap(sortedItems, (groups) => [].concat(...groups));
    76→  const lastSortedItem = flattened[flattened.length - 1];
