   208→    nextToLastToken.loc.end.line === lastToken.loc.start.line ||
   209→    // If there’s no more code after the last import/export the semicolon has to
   210→    // belong to the import/export, even if it is not on the same line.
   211→    sourceCode.getTokenAfter(lastToken) == null;
