   213→  if (semicolonBelongsToNode) {
   214→    return chunk;
   215→  }
   216→
   217→  // Preserve the start position, but use the end position of the `from` string.
   218→  const newLastNode = {
   219→    ...lastNode,
   220→    range: [lastNode.range[0], nextToLastToken.range[1]],
   221→    loc: {
   222→      start: lastNode.loc.start,
   223→      end: nextToLastToken.loc.end,
   224→    },
   225→  };
   226→
   227→  return chunk.slice(0, lastIndex).concat(newLastNode);
